def format_error_json(error: CircuitError, command: str) -> str:
    """Format error as JSON envelope."""
    error_type = type(error).__name__
    result = {
        'ok': False,
        'command': command,
        'exit_code': error.exit_code,
        'error': {
            'type': error_type,
            'message': error.message,
            'file': error.file,
            'line': error.line,
            'col': error.col,
        }
    }
    return json.dumps(result)


def format_version_json() -> str:
    """Format version output as JSON."""
    return json.dumps({'ok': True, 'command': '__version__', 'version': VERSION})


def detect_format(filepath: str, format_override: str) -> str:
    """Detect circuit format from file extension or override.

    Args:
        filepath: Path to the circuit file
        format_override: One of 'auto', 'circ', 'json', 'bench'

    Returns:
        Format string: 'circ', 'json', or 'bench'

    Raises:
        UnknownInputFormatError: If format cannot be determined
    """
    if format_override != 'auto':
        return format_override

    # Determine from file extension
    _, ext = os.path.splitext(filepath)
    ext = ext.lower()

    if ext == '.circ':
        return 'circ'
    elif ext == '.json':
        return 'json'
    elif ext == '.bench':
        return 'bench'
    else:
        raise UnknownInputFormatError(
            f"Unknown input format for file: {filepath}",
            file=filepath
        )


