def format_error_json(error: CircuitError, command: str) -> str:
    """Format error as JSON envelope."""
    error_type = type(error).__name__
    result = {
        'ok': False,
        'command': command,
        'exit_code': error.exit_code,
        'error': {
            'type': error_type,
            'message': error.message,
            'file': error.file,
            'line': error.line,
            'col': error.col,
        }
    }
    return json.dumps(result)


def format_version_json() -> str:
    """Format version output as JSON."""
    return json.dumps({'ok': True, 'command': '__version__', 'version': VERSION})


def detect_format(filepath: str, format_override: str) -> str:
    """Detect circuit format from file extension or override.

    Args:
        filepath: Path to the circuit file
        format_override: One of 'auto', 'circ', 'json', 'bench'

    Returns:
        Format string: 'circ', 'json', or 'bench'

    Raises:
        UnknownInputFormatError: If format cannot be determined
    """
    if format_override != 'auto':
        return format_override

    # Determine from file extension
    _, ext = os.path.splitext(filepath)
    ext = ext.lower()

    if ext == '.circ':
        return 'circ'
    elif ext == '.json':
        return 'json'
    elif ext == '.bench':
        return 'bench'
    else:
        raise UnknownInputFormatError(
            f"Unknown input format for file: {filepath}",
            file=filepath
        )


def cmd_check(filepath: str, json_output: bool, format_flag: str) -> int:
    """Execute check command."""
    # Check file exists first
    if not os.path.exists(filepath):
        if json_output:
            print(format_error_json(
                FileNotFoundError(f"File not found: {filepath}", filepath),
                'check'
            ))
        else:
            print(f"Error: File not found: {filepath}", file=sys.stderr)
        return 1

    try:
        fmt = detect_format(filepath, format_flag)

        if fmt == 'circ':
            declarations, assignments = parse_circ_file(filepath)
        elif fmt == 'json':
            declarations, assignments = parse_json_file(filepath)
        elif fmt == 'bench':
            declarations, assignments = parse_bench_file(filepath)
        else:
            raise UnknownInputFormatError(
                f"Unsupported format: {fmt}",
                file=filepath
            )

        result = validate_circ_file(filepath, declarations, assignments)

        if json_output:
            output = {
                'ok': True,
                'command': 'check',
                'format': fmt,
                'inputs': result['inputs'],
                'outputs': result['outputs'],
            }
            print(json.dumps(output))
        else:
            input_strs = []
            for i in result['inputs']:
                if i['msb'] is not None:
                    input_strs.append(f"{i['name']}[{i['msb']}:{i['lsb']}]")
                else:
                    input_strs.append(i['name'])
            output_strs = []
            for o in result['outputs']:
                if o['msb'] is not None:
                    output_strs.append(f"{o['name']}[{o['msb']}:{o['lsb']}]")
                else:
                    output_strs.append(o['name'])
            print(f"Inputs: {', '.join(input_strs)}")
            print(f"Outputs: {', '.join(output_strs)}")

        return 0

    except CircuitError as e:
        if json_output:
            print(format_error_json(e, 'check'))
        else:
            print(f"Error: {e.message}", file=sys.stderr)
        return e.exit_code


